module top_module(clk, rst, out);input clk;
   input rst;
   output [3:0] out;
   reg [3:0] counter;
   assign out =  counter;

     wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge dbg_halt) begin
      if (rst) begin
         counter <= 0;
      end else begin
         counter <= counter +1;
      end
   end
endmodule
